document.addEventListener("DOMContentLoaded",()=>{let e=document.querySelector(".header");if(!e){console.warn("Header not found after fallback selectors");return}console.log("Header found:",e);let t=0;const n=5,s=e.offsetHeight||60;window.addEventListener("scroll",()=>{let o=window.pageYOffset||document.documentElement.scrollTop;if(Math.abs(t-o)<=n)return;o>t&&o>s?e.style.transform="translateY(-100%)":e.style.transform="translateY(0)",t=o<=0?0:o},{passive:!0})})